"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[97008],{87080:(e,i,n)=>{n.r(i),n.d(i,{data:()=>r});const r={key:"v-3087bbe5",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/05.WebControl.html",title:"自定义控件(五)-WebControl",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/05.WebControl.md"}},40855:(e,i,n)=>{n.r(i),n.d(i,{default:()=>t});const r=(0,n(57293).uE)('<h1 id="自定义控件-五-webcontrol" tabindex="-1"><a class="header-anchor" href="#自定义控件-五-webcontrol" aria-hidden="true">#</a> 自定义控件(五)-WebControl</h1><p>WebControl基础于Control</p><p>Control.Render()在WebControl中一分为三呈现开始标签WebControl.RenderBeginTag(),呈现标签内容WebControl.RenderContents(),呈现结束标签WebControl.RenderEndTag()</p><p>WebControl的TagKey属性决定了RenderBeginTag()方法所生成的HTML标签，默认为span</p><p>通常我们不会重写RenderBeginTag()方法和RenderEndTag()方法</p><p>简单WebControl代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.WebControlTest\n{\n   public class WebControlTest1cs:WebControl\n   {\n\n\n       protected override HtmlTextWriterTag TagKey\n       {\n           get { return HtmlTextWriterTag.Div; }\n       }\n\n       protected override void RenderContents(HtmlTextWriter writer)\n       {\n           writer.Write(&quot;我是WebControl&quot;);\n       }\n   }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853237.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853269.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>不过有些时候需要定义RenderBeginTag,如多重开始标签</p><p>代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.WebControlTest\n{\n   public class WebControlTest1cs:WebControl\n   {\n\n\n       protected override HtmlTextWriterTag TagKey\n       {\n           get { return HtmlTextWriterTag.Div; }\n       }\n       public override void RenderBeginTag(HtmlTextWriter writer)\n       {\n           writer.RenderBeginTag(HtmlTextWriterTag.Table);\n           writer.RenderBeginTag(HtmlTextWriterTag.Tr);\n           writer.RenderBeginTag(HtmlTextWriterTag.Td);\n       }\n       protected override void RenderContents(HtmlTextWriter writer)\n       {\n           writer.Write(&quot;我是多重开始标签&quot;);\n       }\n\n       public override void RenderEndTag(HtmlTextWriter writer)\n       {\n           writer.RenderEndTag();\n           writer.RenderEndTag();\n           writer.RenderEndTag();\n       }\n   }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853227.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853272.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>不过一般不推荐使用这种方法，我们可以通过重写RenderContents()方法来实现</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.WebControlTest\n{\n   public class WebControlTest1cs:WebControl\n   {\n\n\n       protected override HtmlTextWriterTag TagKey\n       {\n           get { return HtmlTextWriterTag.Table; }\n       }\n       protected override void RenderContents(HtmlTextWriter writer)\n       {\n           writer.RenderBeginTag(HtmlTextWriterTag.Tr);\n           writer.RenderBeginTag(HtmlTextWriterTag.Td);\n           writer.Write(&quot;我是多重开始标签&quot;);\n           writer.RenderEndTag();\n           writer.RenderEndTag();\n       }\n\n   }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>WebControl提供了一个AddAttributeToRender()方法在RenderBeginTag()方法之前调用,用来设置控件属性。</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.WebControlTest\n{\n   public class WebControlTest1cs:WebControl\n   {\n\n\n       protected override HtmlTextWriterTag TagKey\n       {\n           get { return HtmlTextWriterTag.Div; }\n       }\n       protected override void AddAttributesToRender(HtmlTextWriter writer)\n       {\n           base.AddAttributesToRender(writer);\n           writer.AddAttribute(&quot;left&quot;,&quot;100px&quot;);\n           writer.AddStyleAttribute(HtmlTextWriterStyle.Width,&quot;100px&quot;);\n           writer.AddStyleAttribute(HtmlTextWriterStyle.Height, &quot;100px&quot;);\n           writer.AddStyleAttribute(HtmlTextWriterStyle.BackgroundColor, &quot;red&quot;);\n       }\n       protected override void RenderContents(HtmlTextWriter writer)\n       {\n\n           writer.Write(&quot;我添加了属性和样式&quot;);\n       }\n\n   }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p>注意：由于AddAttributeToRender()方法实现了对控件基本属性和样式的支持，所以就算需要重写这个方法，也应当调用base.AddAttributeToRender(),以使自定义控件获得基本的功能。</p><p>继承WebControl的相册控件</p><p>代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.WebControlTest\n{\n    public class Albumn : WebControl\n    {\n        protected override HtmlTextWriterTag TagKey\n        {\n            get { return HtmlTextWriterTag.Div; }\n        }\n\n        protected override void AddAttributesToRender(HtmlTextWriter writer)\n        {\n            base.AddAttributesToRender(writer);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.TextAlign, &quot;center&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.Width, &quot;194px&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.Height, &quot;194px&quot;);\n            writer.AddStyleAttribute(&quot;background&quot;, &quot;url(images/background.gif) no-repeat left&quot;);\n        }\n\n        protected override void RenderContents(HtmlTextWriter writer)\n        {\n            writer.AddAttribute(HtmlTextWriterAttribute.Src, &quot;images/nature.jpg&quot;);\n            writer.AddAttribute(HtmlTextWriterAttribute.Width, &quot;160px&quot;);\n            writer.AddAttribute(HtmlTextWriterAttribute.Height, &quot;160px&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.BorderStyle, &quot;none&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.Padding, &quot;0px&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.MarginTop, &quot;16px&quot;);\n            writer.RenderBeginTag(HtmlTextWriterTag.Img);\n            writer.RenderEndTag();\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853286.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>WebControl事件执行顺序</p><p>AddAttributeToRender() //给开始标签添加属性和样式</p><p>RenderBeginTag() //添加开始标签</p><p>RenderContents() //添加内容</p><p>RenderEndTag() //添加结束标签</p>',37),d={},t=(0,n(63243).Z)(d,[["render",function(e,i){return r}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,r]of i)n[e]=r;return n}}}]);